    {
        _ = o switch
        {
           < (uint)0 => 0,
           _ => 2
        };
    }
}

[System.Runtime.CompilerServices.Union]
struct U<T>
{
    private readonly object _value;
    public U(T x) { _value = x; }
    public object Value => _value;
}
";
