  IL_0000:  ldstr      ""2-""
  IL_0005:  call       ""void System.Console.Write(string)""
  IL_000a:  ldloca.s   V_0
  IL_000c:  initobj    ""S1""
  IL_0012:  ldloc.0
  IL_0013:  ret
}
");

            verifier.VerifyIL("Program.Test3", @"
{
  // Code size       20 (0x14)
  .maxstack  1
  .locals init (S1 V_0)
  IL_0000:  ldstr      ""3-""
  IL_0005:  call       ""void System.Console.Write(string)""
  IL_000a:  ldloca.s   V_0
  IL_000c:  initobj    ""S1""
  IL_0012:  ldloc.0
  IL_0013:  ret
}
");

            verifier.VerifyIL("Program.Test4", @"
{
  // Code size       17 (0x11)
  .maxstack  1
