                        S s;
                        s = (S)x; // 3
                        return s;
                    }

                    S M4(in int x)
                    {
                        return (S)x;
                    }

                    S M4s(scoped in int x)
                    {
                        return (S)x; // 4
                    }

                    S M5(in int x)
                    {
                        S s = (S)x;
                        return s;
                    }

                    S M5s(scoped in int x)
