  // Code size       13 (0xd)
  .maxstack  2
  .locals init (int V_0)
  IL_0000:  ldarga.s   V_0
  IL_0002:  ldloca.s   V_0
  IL_0004:  call       ""bool S1.TryGetValue(out int)""
  IL_0009:  ldc.i4.0
  IL_000a:  ceq
  IL_000c:  ret
}
");
        }

